                                <input type="tel" class="form-control" @bind="references[index].Phone" />
                            </div>
                        </div>
                    </div>
                }
                @if (references.Count < 3)
                {
                    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
                }
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
                </div>
            </div>
        </div>
    }

    <!-- Step 4: Cover Letter -->
    @if (currentStep == 3)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">Cover Letter</h5></div>
            <div class="card-body">
                <div class="mb-2">
                    <label for="coverLetter" class="form-label">Write your cover letter</label>
                    <textarea id="coverLetter" class="form-control" rows="10"
                              @bind="coverLetter" @bind:event="oninput"
                              maxlength="2000"></textarea>
                </div>
                <div class="text-muted text-end mb-3">@(coverLetter?.Length ?? 0) / 2000 characters</div>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
                </div>
            </div>
        </div>
    }

    <!-- Step 5: Review & Submit -->
    @if (currentStep == 4)
    {
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">Personal Information</h5>
                <button class="btn btn-sm btn-link" @onclick='() => GoToStep(0)'>Edit</button>
            </div>
            <div class="card-body">
                <dl class="row mb-0">
                    <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@fullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@address</dd>
                </dl>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">Work History</h5>
                <button class="btn btn-sm btn-link" @onclick='() => GoToStep(1)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in workEntries)
                {
                    <div class="mb-3 border-bottom pb-2">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <span class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </span>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mt-1 mb-0">@entry.Description</p>
                        }
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">References</h5>
                <button class="btn btn-sm btn-link" @onclick='() => GoToStep(2)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var r in references)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <span class="text-muted">@r.Email · @r.Phone</span>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">Cover Letter</h5>
                <button class="btn btn-sm btn-link" @onclick='() => GoToStep(3)'>Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@coverLetter</p>
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="Back">Back</button>
            <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@isProcessing">
                @if (isProcessing)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
                }
                Submit Application
            </button>
        </div>
    }
}

<style>
    .step-indicator li {
        position: relative;
    }
    .step-badge {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 2rem;
        height: 2rem;
        border-radius: 50%;
        font-weight: bold;
        font-size: 0.85rem;
    }
    .step-completed:hover .step-badge {
        opacity: 0.8;
    }
</style>

@code {
    private readonly string[] stepLabels = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
    private int currentStep;
    private string? errorMessage;
    private bool isProcessing;
    private bool submitted;
    private int applicationId;

    // Step 1 fields
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2 fields
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };

    // Step 3 fields
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 field
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (step < currentStep)
        {
            errorMessage = null;
            currentStep = step;
        }
    }

    private void Back()
    {
        errorMessage = null;
        if (currentStep > 0) currentStep--;
    }

    private async Task NextFromPersonalInfo()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email) ||
            string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        isProcessing = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(email.Trim());
            if (!emailValid)
            {
                errorMessage = "The email address is not valid. Please enter a valid email.";
                return;
            }
            currentStep = 1;
        }
        finally
        {
            isProcessing = false;
        }
    }

    private void NextFromWorkHistory()
    {
        errorMessage = null;
        foreach (var entry in workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate == default)
            {
                errorMessage = "Please fill in company name, job title, and start date for all positions.";
                return;
            }
        }
        currentStep = 2;
    }

    private void NextFromReferences()
    {
        errorMessage = null;
        foreach (var r in references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        currentStep = 3;
    }

    private void NextFromCoverLetter()
    {
        errorMessage = null;
        if (string.IsNullOrWhiteSpace(coverLetter))
        {
            errorMessage = "Please write a cover letter before proceeding.";
            return;
        }
        currentStep = 4;
    }

    private void AddWorkEntry() => workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (workEntries.Count > 1) workEntries.RemoveAt(index);
    }

    private void AddReference()
    {
        if (references.Count < 3) references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (references.Count > 2) references.RemoveAt(index);
    }

    private async Task SubmitApplication()
    {
        errorMessage = null;
        isProcessing = true;
        try
        {
            var personal = new PersonalInfo(fullName.Trim(), email.Trim(), phone.Trim(), address.Trim());
            var work = new WorkHistory(workEntries.Select(e =>
                new WorkEntry(
                    e.Company.Trim(),
                    e.Title.Trim(),
                    e.StartDate,
                    e.IsCurrent ? null : e.EndDate,
                    e.Description?.Trim() ?? ""
                )).ToList());
            var refs = references.Select(r =>
                new Reference(r.Name.Trim(), r.Relationship.Trim(), r.Email.Trim(), r.Phone.Trim())).ToList();

            var application = new JobApplication(personal, work, refs, coverLetter.Trim());
            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            submitted = true;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isProcessing = false;
        }
    }

    private class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    private class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}
"}

