@page "/apply"
@using sv_0e88d7962414449bbe4f2dde3ad7104b.Models
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<h2 class="mb-4">Job Application</h2>

@if (submitted)
{
    <div class="alert alert-success text-center" role="alert">
        <h4 class="alert-heading">Application Submitted!</h4>
        <p>Your application has been received. Your application ID is <strong>#@applicationId</strong>.</p>
    </div>
}
else
{
    <!-- Step Indicator Bar -->
    <nav class="mb-4" aria-label="Application steps">
        <ol class="d-flex list-unstyled justify-content-between step-indicator">
            @for (int i = 0; i < stepLabels.Length; i++)
            {
                var stepIndex = i;
                var isCurrent = stepIndex == currentStep;
                var isCompleted = stepIndex < currentStep;
                var isFuture = stepIndex > currentStep;

                <li class="text-center flex-fill @(isCurrent ? "step-current" : "") @(isCompleted ? "step-completed" : "") @(isFuture ? "step-future" : "")"
                    @onclick="() => GoToStep(stepIndex)"
                    style="cursor: @(isCompleted ? "pointer" : "default")"
                    role="button"
                    aria-current="@(isCurrent ? "step" : null)">
                    <span class="step-badge @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-secondary text-white")">
                        @if (isCompleted)
                        {
                            <text>✓</text>
                        }
                        else
                        {
                            @(stepIndex + 1)
                        }
                    </span>
                    <div class="small mt-1 @(isFuture ? "text-muted" : "")">@stepLabels[stepIndex]</div>
                </li>
            }
        </ol>
    </nav>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger" role="alert">@errorMessage</div>
    }

    <!-- Step 1: Personal Info -->
    @if (currentStep == 0)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">Personal Information</h5></div>
            <div class="card-body">
                <div class="mb-3">
                    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
                    <input id="fullName" type="text" class="form-control" @bind="fullName" />
                </div>
                <div class="mb-3">
                    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
                    <input id="email" type="email" class="form-control" @bind="email" />
                </div>
                <div class="mb-3">
                    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
                    <input id="phone" type="tel" class="form-control" @bind="phone" />
                </div>
                <div class="mb-3">
                    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
                    <textarea id="address" class="form-control" rows="2" @bind="address"></textarea>
                </div>
                <div class="d-flex justify-content-end">
                    <button class="btn btn-primary" @onclick="NextFromPersonalInfo" disabled="@isProcessing">
                        @if (isProcessing)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
                        }
                        Next
                    </button>
                </div>
            </div>
        </div>
    }

    <!-- Step 2: Work History -->
    @if (currentStep == 1)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">Work History</h5></div>
            <div class="card-body">
                @for (int i = 0; i < workEntries.Count; i++)
                {
                    var index = i;
                    <div class="border rounded p-3 mb-3 position-relative">
                        <h6>Position @(index + 1)</h6>
                        @if (workEntries.Count > 1)
                        {
                            <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                                    @onclick="() => RemoveWorkEntry(index)">Remove</button>
                        }
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                                <input type="text" class="form-control" @bind="workEntries[index].Company" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                                <input type="text" class="form-control" @bind="workEntries[index].Title" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-4">
                                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                                <input type="date" class="form-control" @bind="workEntries[index].StartDate" />
                            </div>
                            <div class="col-md-4">
                                <label class="form-label">End Date</label>
                                <input type="date" class="form-control" @bind="workEntries[index].EndDate"
                                       disabled="@workEntries[index].IsCurrent" />
                            </div>
                            <div class="col-md-4 d-flex align-items-end mb-1">
                                <div class="form-check">
                                    <input class="form-check-input" type="checkbox" id="current-@index"
                                           @bind="workEntries[index].IsCurrent" />
                                    <label class="form-check-label" for="current-@index">Currently working here</label>
                                </div>
                            </div>
                        </div>
                        <div class="mb-2">
                            <label class="form-label">Description</label>
                            <textarea class="form-control" rows="2" @bind="workEntries[index].Description"></textarea>
                        </div>
                    </div>
                }
                <button class="btn btn-outline-secondary mb-3" @onclick="AddWorkEntry">+ Add Another Position</button>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromWorkHistory">Next</button>
                </div>
            </div>
        </div>
    }

    <!-- Step 3: References -->
    @if (currentStep == 2)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">References</h5></div>
            <div class="card-body">
                @for (int i = 0; i < references.Count; i++)
                {
                    var index = i;
                    <div class="border rounded p-3 mb-3 position-relative">
                        <h6>Reference @(index + 1)</h6>
                        @if (references.Count > 2)
                        {
                            <button class="btn btn-sm btn-outline-danger position-absolute top-0 end-0 m-2"
                                    @onclick="() => RemoveReference(index)">Remove</button>
                        }
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Name <span class="text-danger">*</span></label>
                                <input type="text" class="form-control" @bind="references[index].Name" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                                <input type="text" class="form-control" @bind="references[index].Relationship" />
                            </div>
                        </div>
                        <div class="row mb-2">
                            <div class="col-md-6">
                                <label class="form-label">Email <span class="text-danger">*</span></label>
                                <input type="email" class="form-control" @bind="references[index].Email" />
                            </div>
                            <div class="col-md-6">
                                <label class="form-label">Phone <span class="text-danger">*</span></label>
                                <input type="tel" class="form-control" @bind="references[index].Phone" />
                            </div>
                        </div>
                    </div>
                }
                @if (references.Count < 3)
                {
                    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
                }
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromReferences">Next</button>
                </div>
            </div>
        </div>
    }

    <!-- Step 4: Cover Letter -->
    @if (currentStep == 3)
    {
        <div class="card">
            <div class="card-header"><h5 class="mb-0">Cover Letter</h5></div>
            <div class="card-body">
                <div class="mb-2">
                    <label for="coverLetter" class="form-label">Write your cover letter</label>
                    <textarea id="coverLetter" class="form-control" rows="10"
                              @bind="coverLetter" @bind:event="oninput"
                              maxlength="2000"></textarea>
                </div>
                <div class="text-muted text-end mb-3">@(coverLetter?.Length ?? 0) / 2000 characters</div>
                <div class="d-flex justify-content-between">
                    <button class="btn btn-secondary" @onclick="Back">Back</button>
                    <button class="btn btn-primary" @onclick="NextFromCoverLetter">Next</button>
                </div>
            </div>
        </div>
    }

    <!-- Step 5: Review & Submit -->
    @if (currentStep == 4)
    {
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">Personal Information</h5>
                <button class="btn btn-sm btn-link" @onclick='() => GoToStep(0)'>Edit</button>
            </div>
            <div class="card-body">
                <dl class="row mb-0">
                    <dt class="col-sm-3">Full Name</dt><dd class="col-sm-9">@fullName</dd>
                    <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@email</dd>
                    <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@phone</dd>
                    <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@address</dd>
                </dl>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">Work History</h5>
                <button class="btn btn-sm btn-link" @onclick='() => GoToStep(1)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in workEntries)
                {
                    <div class="mb-3 border-bottom pb-2">
                        <strong>@entry.Title</strong> at <strong>@entry.Company</strong><br />
                        <span class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                        </span>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <p class="mt-1 mb-0">@entry.Description</p>
                        }
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">References</h5>
                <button class="btn btn-sm btn-link" @onclick='() => GoToStep(2)'>Edit</button>
            </div>
            <div class="card-body">
                @foreach (var r in references)
                {
                    <div class="mb-2">
                        <strong>@r.Name</strong> — @r.Relationship<br />
                        <span class="text-muted">@r.Email · @r.Phone</span>
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <h5 class="mb-0">Cover Letter</h5>
                <button class="btn btn-sm btn-link" @onclick='() => GoToStep(3)'>Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;">@coverLetter</p>
            </div>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="Back">Back</button>
            <button class="btn btn-success btn-lg" @onclick="SubmitApplication" disabled="@isProcessing">
                @if (isProcessing)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
                }
                Submit Application
            </button>
        </div>
    }
}

<style>
    .step-indicator li {
        position: relative;
    }
    .step-badge {
        display: inline-flex;
        align-items: center;
        justify-content: center;
        width: 2rem;
        height: 2rem;
        border-radius: 50%;
        font-weight: bold;
        font-size: 0.85rem;
    }
    .step-completed:hover .step-badge {
        opacity: 0.8;
