    // Step 3 fields
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4 field
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (step < currentStep)
        {
            errorMessage = null;
            currentStep = step;
        }
    }

    private void Back()
    {
        errorMessage = null;
        if (currentStep > 0) currentStep--;
    }

    private async Task NextFromPersonalInfo()
    {
        errorMessage = null;

        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email) ||
            string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        isProcessing = true;
